## ✅ 2. Fonction Python pour exécuter ce JSON

```python
import importlib
import os
from typing import Any, Dict

def dynamic_run_method(method_config: Dict[str, Any], actual_inputs: Dict[str, Any], language: str = "FR") -> Dict[str, Any]:
    from dotenv import load_dotenv

    # Étape 1 : prévalider les inputs
    required_inputs = {i['name'] for i in method_config.get("inputs", []) if i.get("required")}
    missing = required_inputs - actual_inputs.keys()
    if missing:
        raise ValueError(f"Missing required inputs: {missing}")

    # Étape 2 : valider si un test (ex: path_exists) est demandé
    if method_config.get("validation_method") == "path_exists":
        path = actual_inputs.get("env_path")
        if not os.path.exists(path):
            return {
                "success": False,
                "message": method_config.get("on_failure", {}).get(language, "").format(**actual_inputs)
            }

    # Étape 3 : exécuter la fonction (ici, hardcodée, sinon on pourrait aussi faire un map ou loader dynamique)
    if method_config["name"] == "load_dotenv":
        load_dotenv(dotenv_path=actual_inputs["env_path"])

    # Étape 4 : construire la sortie
    return {
        "success": True,
        "message": method_config.get("on_success", {}).get(language, "").format(**actual_inputs),
        "outputs": [
            {
                "method": {
                    "name": method_config["name"],
                    "inputs": {
                        k: actual_inputs.get(v)
                        for k, v in output["method"]["inputs"].items()
                    }
                }
            }
            for output in method_config.get("outputs", [])
        ]
    }
```

