def format_dict(template, variables):
    """Formate récursivement les chaînes avec des {variables} depuis un dict"""
    if isinstance(template, dict):
        return {k: format_dict(v, variables) for k, v in template.items()}
    elif isinstance(template, list):
        return [format_dict(item, variables) for item in template]
    elif isinstance(template, str):
        return re.sub(r'\{(\w+)\}', lambda m: str(variables.get(m.group(1), m.group(0))), template)
    else:
