def call(object_type, name, **kwargs):
    """Fonction d'exécution - charge et exécute un objet avec injection dynamique"""
    try:
        # Charger le catalogue
        catalog = load_catalog_direct(object_type)
        entry = next((item for item in catalog if item["name"] == name), None)
        if not entry:
            raise ValueError(f"❌ Entrée '{name}' non trouvée dans le catalogue {object_type}.")

        # Vérifier et collecter les inputs requis
        inputs = entry.get("inputs", [])
        input_names = [inp["name"] for inp in inputs]
        missing = [i for i in input_names if i not in kwargs and inp.get("required", True)]
        if missing:
            raise ValueError(f"❌ Paramètres manquants pour {name}: {missing}")

        # Charger dynamiquement le module
        module_path = entry["path"]
        if module_path.endswith(".py"):
            module_path = module_path[:-3]
        module = importlib.import_module(module_path)
        obj = getattr(module, name)

        # Exécuter la fonction avec kwargs filtrés
        call_args = {key: kwargs[key] for key in input_names if key in kwargs}
        result = obj(**call_args) if callable(obj) else obj

        # Gérer les sorties dynamiques
        output_struct = format_dict(entry.get("outputs", {}), kwargs)
        message_success = format_dict(entry.get("on_success", {}), kwargs)
        message_failure = format_dict(entry.get("on_failure", {}), kwargs)

        return {
            "result": result,
            "outputs": output_struct,
            "success_message": message_success,
            "failure_message": message_failure
        }

    except Exception as e:
        print(f"❌ Erreur call({object_type}, {name}): {e}")
        return None
